<template>
     <section class="main-content">
        <loader :is-visible="isLoading"></loader>
            <div  id="divMainLeadData" v-cloak>
            <div class="row">
                    <div class="col-md-12 padding-t_8">
                        <div class="theme-primary partition-full">
                            <span class="p-name text-white">{{$t('manageVendor')}}</span>                           
                        </div>
                    </div>
                </div>
                <div class="border p-3">
                    <Form  ref="form">
                        <dynamic-form lang="en" ref="VendorForm" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit">
                        </dynamic-form>
                        <div class="col-lg-6">
                        <div class="py-2"><small><span class="text-danger">
                                    {{ $t('MandatoryString') }}</span></small>
                        </div>
                        </div>
                        <modalAddProductType v-if="ShowModalAddProductType" @CloseAddProductType="CloseAddProductType"></modalAddProductType>
                    </Form>
                </div>
            </div>
        </section>        
</template>
<script>
import DataService from "../../../services/DataService";
import modalAddProductType from "../../../components/Common/Modal/modalAddProductType.vue";

export default {
     components: { modalAddProductType },
    data() {
        return {
            isLoading:false,
            value: "",
            LeadData: null,
            LeadOwner: null,
            GroupBy: [],
            Channel: null,
            IndustryType: null,
            Status: null,
            selected: false,
            selectoptions: [],
            submited: false,
            vSelectValidate: false,
            vendorId: this.$route.params.id,
            userId:null,
            username:null,
            compnayId:null,
            dateformat:null,
            FormSchema:[],
            ProductTypedata:[],
            productTypeList:[],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success save",
                    text: "<i class='fa fa-save pr-2'></i>Submit",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.onCancel
                }
            ],
            companyId:0,
            ShowModalAddProductType : false,
            FromPage: ''
        };
    },
    created: function () {
        var vm = this;
        this.userId = vm.GetUserInfo.ID;
        this.username = vm.GetUserInfo.Name;
        this.companyId= vm.GetUserInfo.CompanyId;
        this.dateformat= vm.GetUserInfo.DateFormat;
        this.FetchData();
    },
    methods: { 
        onSearch: function (e, selctedValue, search) { 
            var vm = this;
            vm.searchSelectData(search, vm, selctedValue);
        },
        searchSelectData: function (search,ths, selctedValue) {
           
            this.ShowSearchData(search, ths, selctedValue);
        },       
        ShowSearchData: async function (search, ths,selctedValue) { 
            var vm = this;  
            var appendingUrl = `id=&&moduleName=CRM&type=CRM_USERS&search=${search}&refId=`;
            if (typeof (selctedValue) == 'undefined') {
                selctedValue = 0;
            }
            selctedValue.config.options = []; 
            await DataService.getDDLData(appendingUrl).then(function (response) { 
                selctedValue.config.options = [];                
                if (response.data) {
                    vm.JsonObj = response.data;
                    if (vm.JsonObj != null) {
                        response.data.DATA.forEach((item) => {
                            var obj = {
                                value: item.value,
                                name: item.name
                            }                            
                            selctedValue.config.options.push(obj);                           
                        })
                        vm.$refs.VendorForm.UpdateKeyValue();
                    }
                }
            });
        },         
        onSubmit(formfields, val) { 
            var vm = this;
            this.$refs.form.validate().then((result) => {
                if (result) {
                    vm.isLoading=true;
                    var CustomFieldArray = vm.$refs.VendorForm.ConvertDynamicFormObjToCustomFieldObj(vm.FormSchema);
                    CustomFieldArray.forEach((x) => {
                        // if (vm.$route.params.id == '0') {
                        //     if (x.field_name == "created_by") {
                        //         x.field_value = vm.userId;
                        //     }

                        // } else {
                        //     if (x.field_name == 'modified_by') {
                        //         x.field_value = vm.userId;
                        //     }
                        // }
                        // if (x.field_name == 'created_by') {
                        //     x.field_value = vm.userId;
                        // }                        
                        if (x.field_name == 'company_id') {
                            x.field_value = vm.companyId;
                        }
                        if (x.field_name == 'vendor_id') {
                            x.field_value = vm.vendorId;
                        }
                        if (x.field_name == "vendor_owner") {
                            if (!vm.isBlank(x.field_value)) {
                                x.field_value = x.field_value.value;
                            }
                        }
                        if (x.field_name == "ProductType") {   
                                if (!vm.isBlank(x.field_value) && x.field_value.length > 0) {
                                    var productTypeId = '';
                                    x.field_value.forEach((row) => {
                                        productTypeId += row.value + ', ';
                                    });
                                    productTypeId = productTypeId.slice(0, -2);
                                    x.field_value = productTypeId;
                                }
                        }
                        if(vm.vendorId>0){
                            if (x.field_name == 'modified_by') {
                                 x.field_value = vm.userId;
                            }
                        }
                    });
                    var postJSON = {
                        data: CustomFieldArray                     
                    };
                    var objectPostString = JSON.stringify(postJSON);
                    DataService.SaveVendor(objectPostString).then(response => { 
                        vm.isLoading=false;             
                        if (response.data[0].Code == "1") {
                            if (vm.vendorId > 0) {                               
                                vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('Vendor')]), "success", true, vm.$t("Alert"));
                            }
                            else {                               
                                vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Vendor')]), "success", true, vm.$t("Alert"));
                            }
                            vm.$router.push({ name: 'CRMVendor' });
                        }
                        else {                           
                            vm.ShowAlert(vm.$t('AddedError', [vm.$t('Vendor')]), "failure", true, vm.$t("Alert"));   
                        }                        
                    })
                }
            });
        },
        onCancel: function () {
            this.$router.push({ name: 'CRMVendor' });
        },
        AddProductType: function(){
            var vm = this;
            vm.ShowModalAddProductType = true;
        },
        CloseAddProductType (){
            debugger;
            this.ShowModalAddProductType = false;
            this.FetchData();
            
        },
        FetchData: function () {  
            debugger;           
            var vm = this;
            vm.isLoading=true;
            const params = `recordId=${vm.$route.params.id}&moduleName=CRM&subModuleCode=CRM_VENDORS&langCode=en`;
            DataService.GetDynamicForm(params)
                .then(function (response) {   
                    vm.isLoading=false;
                    vm.FormSchema = vm.$refs.VendorForm.ConvertCustomFieldIntoDynamicFormObj(response.data.data); 
                    vm.FormSchema.forEach((group, gi) => {
                        group.Data.forEach(async  (field, fi) => {  
                            if (field.name == 'is_online_vendor' && field.value == '') {
                                field.value = '0';
                            }
                            if (field.name == 'status_id' && field.value == '') {
                                field.value = field.config.options.filter(x => x.name.toLowerCase() == 'active')[0].value;                               
                            }    
                            if(field.name == 'ProductType'){
                                debugger
                                field.config.showAddIcon = true;
                                field.config.onAddButtonClick = vm.AddProductType;
                            }
                            if (field.name == 'ProductType' && vm.$route.params.id !== '0') {
                                debugger
                                var ProductTypedata = response.data.productTypeList;
                                if (!vm.isBlank(ProductTypedata)) {
                                    var bindProductType = [];

                                    vm.productTypeList = field.config.options.filter(f =>
                                        ProductTypedata.includes(Number(f.value))
                                    );

                                    vm.productTypeList.forEach((item) => {
                                        bindProductType.push({
                                            value: item.value,
                                            label: item.name
                                        });
                                    });

                                    field.value = bindProductType;
                                }

                            }                         
                            if (field.name == "vendor_owner") {
                            if (field.value == '') {
                                field.value = { label: vm.username, value: vm.userid }
                            }
                            else {
                                if (field.config.options != null) {
                                    var obj = field.config.options.filter(x => x.value == field.value)[0];
                                    field.value = { label: obj.name, value: obj.value }
                                } else {
                                    field.value = { label: vm.username, value: vm.userid }
                                }
                            }
                            field.config.onSearchChange = vm.onSearch;                             
                            vm.onSearch(null,field," ");
                        }
                            field.config.onChange = vm.onChangeEventForFields;
                        })
                    })
                })
        },
    },
}
</script>

      
   